// Resolve service filter from query param ?service=
const query = $input.first().json.query || {};
const service = (query.service || 'all').toLowerCase();
const valid = ['all', 'auth', 'nlp', 'ocr', 'crawl4ai', 'n8n', 'supabase'];
if (!valid.includes(service)) throw new Error('Invalid service. Must be: ' + valid.join(' | '));
return { json: { service } };

const health = $input.first().json;
const status = health.status === 'healthy' || health.status === 'ok' ? 'healthy' : 'degraded';

const catalogue = [
  { method: 'GET',  path: '/health',                    description: 'Detailed health check with DB and Supabase status' },
  { method: 'GET',  path: '/status',                    description: 'Version and uptime info' },
  { method: 'GET',  path: '/verify',                    description: 'Verify JWT token (used by Caddy forward_auth)' },
  { method: 'POST', path: '/control/backup',            description: 'Trigger database backup' },
  { method: 'GET',  path: '/control/backup/status',     description: 'Get last backup status' },
  { method: 'GET',  path: '/control/backup/list',       description: 'List available backup archives' },
  { method: 'GET',  path: '/control/backup/files',      description: 'List files in backup' },
  { method: 'GET',  path: '/control/backup/diff',       description: 'Diff between two backups' },
  { method: 'GET',  path: '/control/users',             description: 'List Supabase users' },
  { method: 'POST', path: '/control/users',             description: 'Create a new user' },
  { method: 'POST', path: '/control/users/password',    description: 'Change user password' },
  { method: 'POST', path: '/control/users/delete',      description: 'Delete user' },
  { method: 'GET',  path: '/control/services/status',   description: 'List all Docker service statuses' },
  { method: 'POST', path: '/control/services/{svc}/{action}', description: 'Start/stop/restart a service' },
  { method: 'GET',  path: '/control/services/{svc}/logs', description: 'Tail service logs' },
  { method: 'GET',  path: '/control/macros',            description: 'List available control macros' },
  { method: 'POST', path: '/control/macro/{id}',        description: 'Execute a control macro' },
  { method: 'POST', path: '/control/restore',           description: 'Restore database from backup' }
];

return {
  json: {
    service: 'auth-gateway',
    base_url: 'http://auth-gateway:5001',
    status,
    health_raw: health,
    endpoints: catalogue
  }
};

const health = $input.first().json;
const status = health.status === 'healthy' || health.status === 'ok' ? 'healthy' : 'degraded';

const catalogue = [
  { method: 'GET',  path: '/health',              description: 'Health check' },
  { method: 'GET',  path: '/status',              description: 'Service status and version' },
  { method: 'POST', path: '/process',             description: 'Analyse document (PDF or text), extract metadata + NLP' },
