  { method: 'POST', path: '/pdf/extract',         description: 'Extract text from PDF (native or OCR fallback)' },
  { method: 'POST', path: '/document/analyze',    description: 'Full document analysis pipeline (NLP + layout)' },
  { method: 'POST', path: '/graph/init',           description: 'Initialize Neo4j graph schema and indexes' },
  { method: 'POST', path: '/graph/index',          description: 'Index Obsidian note into Neo4j knowledge graph' },
  { method: 'POST', path: '/graph/query',          description: 'Query knowledge graph by entities or title similarity' }
];

return {
  json: {
    service: 'python-nlp-service',
    base_url: 'http://python-nlp-service:8001',
    status,
    health_raw: health,
    endpoints: catalogue
  }
};

const health = $input.first().json;
const status = health.status === 'healthy' ? 'healthy' : 'degraded';

const catalogue = [
  { method: 'GET',  path: '/',                    description: 'Root health check' },
  { method: 'GET',  path: '/health',              description: 'Detailed health: engines, dirs, model status' },
  { method: 'GET',  path: '/engines',             description: 'List available OCR engines and their status' },
  { method: 'GET',  path: '/stats',               description: 'Processing statistics and counters' },
  { method: 'POST', path: '/ocr/process',         description: 'Process single image/file with OCR (TrOCR / Tesseract / auto)' },
  { method: 'POST', path: '/ocr/batch',           description: 'Batch-process multiple files' },
  { method: 'POST', path: '/ocr/process-folder',  description: 'Process all files in an /data/input sub-folder' },
  { method: 'POST', path: '/pdf/analyze',         description: 'Analyse PDF: extract text and/or run OCR per page' },
  { method: 'POST', path: '/pdf/analyze-type',    description: 'Classify PDF as digital / scanned / mixed' },
  { method: 'POST', path: '/pdf/to-png',          description: 'Convert specific PDF pages to PNG' },
  { method: 'POST', path: '/pdf/to-png-all',      description: 'Convert all PDF pages to PNG' },
  { method: 'GET',  path: '/pdf/page-count',      description: 'Get page count for a PDF file' },
  { method: 'POST', path: '/pdf/to-png-combined', description: 'Convert PDF and combine pages into one image' },
  { method: 'POST', path: '/pdf/to-png-smart',    description: 'Smart PDF-to-PNG: auto quality, size constraints' },
  { method: 'POST', path: '/debug/file-info',     description: 'Debug: show file metadata and format details' }
];

return {
  json: {
    service: 'ocr-service',
    base_url: 'http://ocr-service:8002',
    status,
    health_raw: health,
    available_engines: health.available_engines || [],
    endpoints: catalogue
  }
};

const health = $input.first().json;
const status = health.status === 'ok' || health.status === 'healthy' ? 'healthy' : 'degraded';

const catalogue = [
  { method: 'GET',  path: '/health',   description: 'Health check and version info' },
  { method: 'POST', path: '/crawl',    description: 'Start crawl job (CSS or LLM extraction strategy)' },
  { method: 'GET',  path: '/task/{id}',description: 'Get status/result of an async crawl task' },
  { method: 'GET',  path: '/tasks',    description: 'List all active crawl tasks' },
  { method: 'DELETE',path: '/task/{id}',description: 'Cancel a crawl task' }
];

return {
  json: {
    service: 'crawl4ai',
    base_url: 'http://crawl4ai:11235',
    status,
    health_raw: health,
    endpoints: catalogue
  }
};

// Build structured response
const items = $input.all();

// Single-service branches produce one item; all-branch produces 4 items
const services = items.map(item => item.json).filter(s => s.service);

const response = {
  generated_at: new Date().toISOString(),
  total_services: services.length,
  services
};

return { json: response };
